  <style>
    /* Reset rapide */
    * {
      margin: 0;
      padding: 0;
      box-sizing: border-box;
    }
    html, body {
      height: 100%;
      font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
      background: linear-gradient(135deg, #9b7030, #7a5621);
      color: #ffffff;
    }
    body {
      display: flex;
      align-items: center;
      justify-content: center;
      text-align: center;
      padding: 1rem;
    }
    .container {
      max-width: 600px;
      background: #35281A;
      padding: 2rem;
      box-shadow: 0 8px 20px rgba(0,0,0,0.3);
    }
    h1 {
      font-size: 1.5rem;
      margin: 1rem;
    }
    p {
      font-size: 1.1rem;
      line-height: 1.5;
    }
    hr {
        margin: 1rem 0;
    }
    /* Responsive */
    @media (max-width: 400px) {
      h1 { font-size: 1.5rem; }
      p { font-size: 1rem; }
    }
  </style>
